const WARM=['#e8d4a0','#c4894a','#8b4a2a','#f5e6c8','#d4a574'];
const COOL=['#4a6670','#8a9ba0'];
const SHADOW='#2a1f14';
let puffs=[];
function setup(){ createCanvas(500,500); noStroke(); for(let i=0;i<14;i++) puffs.push({x:random(120,380),y:random(120,460),r:random(20,55),s:random(0.0008,0.0022),ph:random(TWO_PI)}); }
function draw(){
  // cold glass pane
  background(SHADOW);
  // pane wash
  noStroke();
  fill(COOL[0]+'66');
  rect(40,30,420,440,6);
  // condensation frame
  fill(COOL[1]+'22'); rect(40,30,420,440,6);
  const intensity = (window.features && window.features.hijaz_intensity) || 0;
  const amp = (window.features && window.features.amplitude) || 0;
  // soft breath bloom — translucent warm pale halos rising
  for(let p of puffs){
    p.y -= p.s*60*(0.4+intensity*1.2);
    if(p.y < 60) { p.y = 470; p.x = random(120,380); }
    const a = 60 + intensity*120 + sin(millis()*0.001+p.ph)*20;
    fill(WARM[3]+hex(constrain(int(a),0,200),2));
    ellipse(p.x,p.y,p.r*(1+intensity*0.4));
  }
  // a faint fingertip-traced vertical line — breath gathering
  stroke(WARM[3]+'55'); strokeWeight(1.2); noFill();
  const cx = 250 + sin(millis()*0.0006)*18;
  line(cx, 380, cx, 180 - intensity*30);
  noStroke();
}
function hex(n,w){ let s=n.toString(16); while(s.length<w) s='0'+s; return s; }
